COMP2011_ch8_12:
Factorial Function: Recursive vs. Non-Recursive
int factorial(int n)
/* factorial.cpp */
{
if (n < 0)
// Error checking
return -1;
else if (n == 0)
// Base case; ending case too!
return 1;
else
// Recursive case
return n * factorial(n-1);
}
int factorial(int n)
/* non-recursive-factorial.cpp */
{
int result = 1;
// Default value for n = 0 or 1
if (n < 0)
// Error checking
return -1;
for (int j = 2; j <= n; j++) // When n >= 2
result *= j;
return result;
}
