/* To find the 2D Euclidean distance between 2 points */
double euclidean_distance(const Point& p1, const Point& p2)
{
double x_diff = p1.x - p2.x, y_diff = p1.y - p2.y;
return sqrt(x_diff*x_diff + y_diff*y_diff);
}
